mapper.select:
SELECT a.bom_id as bomId ,a.item_cd ,a.bom_ver ,b.item_name ,b.unit ,req.qty ,b.item_type_cd FROM tb_bom_mst a INNER JOIN tb_item_mst b ON b.item_cd = a.item_cd INNER JOIN (
SELECT #{item.itemCd} AS item_cd, #{item.qty} AS qty
) req ON req.item_cd = a.item_cd WHERE a.default_yn = 'Y'

with bom_qty as ( select x.item_cd ,sum(x.reqQty) as reqQty from (
select b.item_cd, case when c.item_type_cd = 'M1' then sum(b.real_content) * #{item.qty} / 100 else sum(b.qty) * #{item.qty} / 100 end as reqQty from tb_bom_mst a join tb_bom_recipe b on a.bom_id = b.bom_id join tb_item_mst c on c.item_cd = b.item_cd and c.item_type_cd in ('M1', 'M2', 'M7') where a.default_yn = 'Y' and a.bom_id = #{item.bomId} and b.item_cd not in ('JRW00215', 'JRMSC00011') group by b.item_cd, c.item_type_cd
) x group by x.item_cd ) select b.item_cd as itemCd ,c.code_nm as itemTypeName ,b.item_name as itemName ,b.spec ,isnull(f.qty, 0 ) as realStockQty ,isnull(a.reqQty, 0) reqQty ,isnull(f.qty, 0 )-isnull(a.reqQty, 0) as differenceQty ,isnull( g.reserveStockQty, 0 ) as reserveStockQty ,e.customer_name as customerName ,d.code_nm as orderType ,isnull(b.in_price, 0) as inPrice from bom_qty a inner join tb_item_mst b on b.item_cd = a.item_cd inner join tb_common_code c on c.code = b.item_type_cd and c.com_type_cd = 'item_Type_cd' left join tb_common_code d on d.code = b.item_grp1 and d.com_type_cd = 'ITEM_GRP1' left join tb_customer e on e.customer_cd = b.customer_cd left join ( select item_cd, sum(qty) as qty from vw_inv_stock_tran group by item_cd ) f on f.item_cd = a.item_cd left join ( select item_cd ,sum(qty) as reserveStockQty from tb_pur_order_item where in_yn ='N' group by item_cd ) g on g.item_cd = a.item_cd order by e.customer_name desc
